const express = require('express');
const winston = require('winston');
require('express-winston');

const app = express();
const port = 3000;

// Configure Winston logger
const logger = winston.createLogger({
  level: 'info',
  format: winston.format.json(),
  transports: [
    new winston.transports.File({ filename: 'app.log' })
  ]
});

if (process.env.NODE_ENV !== 'production') {
  logger.add(new winston.transports.Console({
    format: winston.format.simple()
  }));
}

// Middleware to log requests using Winston
app.use(expressWinston.logger({
  winstonInstance: logger,
  msg: "HTTP {{req.method}} {{res.statusCode}} {{res.responseTime ms}} {{req.url}}"
}));

// Route to accept user input and log it
app.post('/log', (req, res) => {
  const { username, ip, customHeader } = req.body;
  logger.info({ username, ip, customHeader });
  res.send('Log data received');
});

app.listen(port, () => {
  console.log(`Server running at http://localhost:${port}/`);
});